@@ -11,6 +14,21 @@ const segments = currentPath.split('/').filter(Boolean);
 // Don't show breadcrumbs on the home page
 const isHomePage = currentPath === '/' || segments.length === 0;

+// Get search weight configuration for pagefind metadata
+const { starlightRoute } = Astro.locals;
+const weightConfig = getSearchWeight(starlightRoute.id);
+const pagefindType = weightConfig?.metadata?.type;
+const pagefindWeight = weightConfig?.weight;
+
+// Build h1 attributes
+const h1Attrs: Record<string, any> = {
+  id: PAGE_TITLE_ID,
+  'data-pagefind-meta': 'title'
+};
+if (pagefindWeight !== undefined) {
+  h1Attrs['data-pagefind-weight'] = pagefindWeight * 100000;
+}
+
 // Build customization array for breadcrumb links
